sn_aia_tool.script:
(function(inputs) {
    var results = [];
    var keywords = inputs.search_terms.toLowerCase().split(' ');
    var gr = new GlideRecord('kb_knowledge');
    gr.addQuery('kb_knowledge_base.title', 'Medtric Warranty Policies');
    gr.addQuery('workflow_state', 'published');
    gr.addQuery('active', true);
    gr.query();
    while (gr.next()) {
        var text = (gr.getValue('text') || '').toLowerCase();
        var title = (gr.getValue('short_description') || '').toLowerCase();
        var matchCount = 0;
        for (var i = 0; i < keywords.length; i++) {
            if (keywords[i].length > 2 && (text.indexOf(keywords[i]) >= 0 || title.indexOf(keywords[i]) >= 0)) {
                matchCount++;
            }
        }
        if (matchCount > 0) {
            results.push({
                title: gr.getValue('short_description'),
                number: gr.getValue('number'),
                text: gr.getValue('text').replace(/<[^>]*>/g, '').substring(0, 800),
                relevance: matchCount
            });
        }
    }
    results.sort(function(a, b) { return b.relevance - a.relevance; });
    if (results.length === 0) {
        return JSON.stringify({ status: 'no_results', message: 'No relevant KB articles found for: ' + inputs.search_terms });
    }
    return JSON.stringify({ status: 'success', articles: results.slice(0, 3) });
})(inputs);
